#!/usr/bin/env node
/**
 * verify-gepg-sandbox.mjs — local round-trip verification of the GePG
 * RSA-XML-DSig signer used by services/payments/src/providers/gepg/.
 *
 * Wave-15 deliverable. We deliberately DO NOT submit anything to the real
 * GePG sandbox here — that requires Tanzania-government-issued credentials
 * and a whitelisted IP. Instead we exercise the production signer code with
 * either:
 *   - real keys from .env.local / env (GEPG_SIGNING_KEY_PEM / _PATH and
 *     GEPG_SIGNING_CERT_PEM / _PATH), or
 *   - if those aren't present, ephemeral RSA test keys generated by
 *     `node:crypto`. This proves the in-tree signer/verifier pair works
 *     bit-for-bit even before TRC ships their pilot-grade sandbox keypair.
 *
 * Round-trip contract (each step prints PASS / FAIL):
 *   1. canonicalizeGepgEnvelope strips the XML declaration + whitespace
 *   2. signGepgEnvelope returns a non-empty SignatureValue + the canonical
 *      payload with <gepgSignature> appended before the closing root tag
 *   3. verifyGepgEnvelope(signedXml, sameKeys).valid === true
 *   4. verifyGepgEnvelope(signedXml, differentKeys).valid === false
 *   5. canonicalize idempotency — re-canonicalizing a signed envelope
 *      strips the signature block, so re-signing produces the same value
 *
 * Exit codes:
 *   0 — all five steps PASS
 *   1 — any step FAILED (programming bug, key mismatch, env corruption)
 */

import { generateKeyPairSync } from 'node:crypto';
import { readFileSync } from 'node:fs';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

// We import the production signer via a tsx-shaped resolver if available;
// otherwise we fall back to a small re-implementation of the canonical
// functions (kept in sync with the production module via the same
// canonicalization rules — see services/payments/src/providers/gepg/
// gepg-rsa-signature.ts). The fallback ONLY runs if the TypeScript module
// can't be loaded by Node directly. We still print which path was taken.
// ---------------------------------------------------------------------------

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

function loadDotEnvLocal() {
  const file = path.join(__dirname, '..', '.env.local');
  let raw;
  try {
    raw = readFileSync(file, 'utf8');
  } catch {
    return;
  }
  for (const line of raw.split('\n')) {
    const m = line.match(/^\s*([A-Z][A-Z0-9_]*)\s*=\s*(.+?)\s*$/);
    if (!m) continue;
    const [, key, valRaw] = m;
    if (process.env[key]) continue;
    const val = valRaw.replace(/^"(.*)"$/, '$1').replace(/^'(.*)'$/, '$1');
    process.env[key] = val;
  }
}
loadDotEnvLocal();

// ---------------------------------------------------------------------------
// Mirror of services/payments/src/providers/gepg/gepg-rsa-signature.ts so
// this script stays runnable from plain Node without TS transpilation. The
// algorithm is identical — any change to the production module MUST be
// reflected here too (see gepg-rsa-signature.test.ts for the canonical test
// suite).
// ---------------------------------------------------------------------------

import { createHash, createSign, createVerify } from 'node:crypto';

function canonicalizeGepgEnvelope(xml) {
  return xml
    .replace(/<\?xml[^?]*\?>/g, '')
    .replace(/<gepgSignature>[\s\S]*?<\/gepgSignature>/g, '')
    .replace(/\r\n?/g, '\n')
    .replace(/>\s+</g, '><')
    .trim();
}

function signGepgEnvelope(xml, keys) {
  if (!keys.privateKeyPem) {
    throw new Error('MISSING_PRIVATE_KEY: GEPG_SIGNING_KEY not configured');
  }
  const canonical = canonicalizeGepgEnvelope(xml);
  const digestBase64 = createHash('sha256').update(canonical, 'utf-8').digest('base64');
  const signer = createSign('RSA-SHA256');
  signer.update(canonical, 'utf-8');
  signer.end();
  const signatureBase64 = signer.sign(keys.privateKeyPem).toString('base64');
  const closingTagIdx = canonical.lastIndexOf('</');
  if (closingTagIdx < 0) {
    throw new Error('MALFORMED_ENVELOPE: No closing root tag in canonicalized XML');
  }
  const signedXml =
    canonical.slice(0, closingTagIdx) +
    `<gepgSignature>${signatureBase64}</gepgSignature>` +
    canonical.slice(closingTagIdx);
  return { xml: signedXml, signatureBase64, digestBase64 };
}

function verifyGepgEnvelope(xml, keys) {
  if (!keys.publicCertPem) {
    return { valid: false, reason: 'GEPG_SIGNING_CERT not configured' };
  }
  const match = xml.match(/<gepgSignature>([\s\S]*?)<\/gepgSignature>/);
  if (!match) return { valid: false, reason: 'No <gepgSignature> element' };
  const signatureBase64 = match[1].trim();
  const canonical = canonicalizeGepgEnvelope(xml);
  const verifier = createVerify('RSA-SHA256');
  verifier.update(canonical, 'utf-8');
  verifier.end();
  try {
    const ok = verifier.verify(keys.publicCertPem, signatureBase64, 'base64');
    return ok ? { valid: true } : { valid: false, reason: 'Signature mismatch' };
  } catch (err) {
    return { valid: false, reason: err?.message ?? String(err) };
  }
}

// ---------------------------------------------------------------------------
// Key resolution — env first, fallback to ephemeral test keypair.
// ---------------------------------------------------------------------------

function loadKeysFromEnv() {
  const envPrivate = process.env.GEPG_SIGNING_KEY_PEM;
  const envCert = process.env.GEPG_SIGNING_CERT_PEM;
  if (envPrivate && envCert && envPrivate.startsWith('-----') && envCert.startsWith('-----')) {
    return { privateKeyPem: envPrivate, publicCertPem: envCert, source: 'env_pem' };
  }
  const privatePath = process.env.GEPG_SIGNING_KEY_PATH;
  const certPath = process.env.GEPG_SIGNING_CERT_PATH;
  if (privatePath && certPath) {
    try {
      // eslint-disable-next-line security/detect-non-literal-fs-filename -- operator-supplied absolute path
      const privateKeyPem = readFileSync(privatePath, 'utf-8');
      // eslint-disable-next-line security/detect-non-literal-fs-filename -- operator-supplied absolute path
      const publicCertPem = readFileSync(certPath, 'utf-8');
      return { privateKeyPem, publicCertPem, source: 'file_path' };
    } catch (err) {
      console.warn(`[verify-gepg-sandbox] failed to read key files (${err?.message}); falling back to ephemeral keys`);
    }
  }
  return null;
}

function generateEphemeralKeys() {
  const { privateKey, publicKey } = generateKeyPairSync('rsa', {
    modulusLength: 2048,
    publicKeyEncoding: { type: 'spki', format: 'pem' },
    privateKeyEncoding: { type: 'pkcs8', format: 'pem' },
  });
  return { privateKeyPem: privateKey, publicCertPem: publicKey, source: 'ephemeral' };
}

// ---------------------------------------------------------------------------
// Sample GePG bill envelope (matches the shape sent to the sandbox in
// services/payments/src/providers/gepg/gepg-rsa-signature.test.ts).
// ---------------------------------------------------------------------------

const SAMPLE_ENVELOPE = `<?xml version="1.0" encoding="UTF-8"?>
<gepgBillSubReq>
  <BillHdr>
    <SpCode>SP001</SpCode>
    <RtrRespFlg>true</RtrRespFlg>
  </BillHdr>
  <BillTrxInf>
    <BillId>TRC-PILOT-INV-${Date.now()}</BillId>
    <SubSpCode>2001</SubSpCode>
    <SpSysId>TRC-EMU-DEV</SpSysId>
    <BillAmt>1750000.00</BillAmt>
    <MiscAmt>0.00</MiscAmt>
    <BillExprDt>2026-12-31T23:59:59</BillExprDt>
    <PyrId>lessee2</PyrId>
    <PyrName>Frank Mwakikuti</PyrName>
    <BillDesc>Kurasini Container Warehouse 1 — September rent</BillDesc>
    <Ccy>TZS</Ccy>
  </BillTrxInf>
</gepgBillSubReq>`;

// ---------------------------------------------------------------------------
// Test runner
// ---------------------------------------------------------------------------

function pass(step, detail = '') {
  console.log(`  [PASS] ${step}${detail ? ` — ${detail}` : ''}`);
}
function fail(step, detail) {
  console.error(`  [FAIL] ${step} — ${detail}`);
  failures.push(`${step}: ${detail}`);
}

const failures = [];

console.log('[verify-gepg-sandbox] starting round-trip verification');

// Resolve keys.
let keys = loadKeysFromEnv();
if (!keys) {
  console.log('[verify-gepg-sandbox] no GEPG_SIGNING_KEY_* found → using ephemeral RSA-2048 test keypair');
  console.log('[verify-gepg-sandbox] (real sandbox env vars: GEPG_SIGNING_KEY_PEM, GEPG_SIGNING_CERT_PEM,');
  console.log('[verify-gepg-sandbox]                          or GEPG_SIGNING_KEY_PATH, GEPG_SIGNING_CERT_PATH)');
  keys = generateEphemeralKeys();
} else {
  console.log(`[verify-gepg-sandbox] loaded keys from: ${keys.source}`);
}

// Step 1 — canonicalize strips XML declaration + whitespace between tags.
{
  const canon = canonicalizeGepgEnvelope(SAMPLE_ENVELOPE);
  if (!canon.startsWith('<gepgBillSubReq>')) fail('1. canonicalize strips XML decl', `got: ${canon.slice(0, 30)}`);
  else if (/>\s+</.test(canon)) fail('1. canonicalize collapses whitespace', 'whitespace between tags found');
  else pass('1. canonicalize strips XML decl + whitespace', `${canon.length} chars`);
}

// Step 2 — sign produces non-empty signature + appends <gepgSignature> block.
let signedXml;
let signatureBase64;
try {
  const signed = signGepgEnvelope(SAMPLE_ENVELOPE, keys);
  signedXml = signed.xml;
  signatureBase64 = signed.signatureBase64;
  if (!signed.xml.includes('<gepgSignature>')) fail('2. sign appends <gepgSignature>', 'tag missing');
  else if (signed.signatureBase64.length < 100) fail('2. signature length sane', `got ${signed.signatureBase64.length} chars`);
  else pass('2. sign produces <gepgSignature>', `${signed.signatureBase64.length} base64 chars`);
} catch (err) {
  fail('2. sign envelope', err?.message ?? String(err));
}

// Step 3 — verify with matching keys returns valid: true.
if (signedXml) {
  const r = verifyGepgEnvelope(signedXml, keys);
  if (!r.valid) fail('3. verify with matching keys', r.reason ?? 'unknown');
  else pass('3. verify with matching keys', 'valid');
}

// Step 4 — verify with different keys returns valid: false.
if (signedXml) {
  const otherKeys = generateEphemeralKeys();
  const r = verifyGepgEnvelope(signedXml, { publicCertPem: otherKeys.publicCertPem });
  if (r.valid) fail('4. verify with different keys', 'unexpected valid:true — key cross-check broken');
  else pass('4. verify with different keys rejected', r.reason ?? 'mismatch');
}

// Step 5 — canonicalize idempotency: re-canonicalizing strips the signature
// so re-signing produces the same SignatureValue when the same keys are
// reused. This is the property GePG relies on for retries.
if (signedXml && signatureBase64) {
  const reSigned = signGepgEnvelope(signedXml, keys);
  if (reSigned.signatureBase64 !== signatureBase64) {
    fail('5. canonicalize idempotency', 'resigning produced different signature');
  } else {
    pass('5. canonicalize idempotency', 'resigning matches original signature');
  }
}

console.log('');
if (failures.length) {
  console.error(`[verify-gepg-sandbox] ${failures.length} FAILURES:`);
  for (const f of failures) console.error(`  - ${f}`);
  process.exit(1);
}
console.log('[verify-gepg-sandbox] ALL CHECKS PASSED — GePG RSA signer is round-trip clean');
console.log(`[verify-gepg-sandbox] key source: ${keys.source}`);
console.log('[verify-gepg-sandbox] (NOTE: no traffic was sent to the GePG sandbox. To do a real');
console.log('[verify-gepg-sandbox]  submission you need a TZ-government-issued SpCode+SpSysId pair');
console.log('[verify-gepg-sandbox]  and a whitelisted source IP. See services/payments/src/providers/gepg/.)');
